if (customerName !== (input.customerName ?? input.requesterName ?? '')) normalizedFields.push('customerName');

const email = normalizeText(input.email ?? input.requesterEmail).toLowerCase();
if (email !== (input.email ?? input.requesterEmail ?? '')) normalizedFields.push('email');

const message = normalizeSpaces(normalizeText(input.message));
if (message !== (input.message ?? '')) normalizedFields.push('message');

const deptRaw = normalizeText(input.department).toUpperCase();
const department = deptRaw || 'GENERAL';
if (!deptRaw) warnings.push('department_missing_defaulted_GENERAL');
if (department !== (input.department ?? '')) normalizedFields.push('department');

const urgencyRaw = normalizeText(input.urgency).toUpperCase();
const urgency = urgencyRaw || 'UNKNOWN';
if (!urgencyRaw) warnings.push('urgency_missing_defaulted_UNKNOWN');
if (urgency !== (input.urgency ?? '')) normalizedFields.push('urgency');

const requestType = normalizeText(input.requestType);
const source = normalizeText(input.source).toLowerCase() || 'website-form';

const traceId = `${ticketId}-${now.getTime()}`;

